type TranslationFn = ReturnType<typeof useTranslation>["t"];

const DEX_PERIODS: DexPeriod[] = ["daily", "weekly", "30d", "90d"];

function getPeriodLabel(period: DexPeriod, t: TranslationFn): string {
  if (period === "daily") return t("board.period.daily");
  if (period === "weekly") return t("board.period.weekly");
  if (period === "30d") return t("board.period.30d");
  return t("board.period.90d");
}

function isDexPeriod(value: string | null): value is DexPeriod {
  return (
    value === "daily" ||
    value === "weekly" ||
    value === "30d" ||
    value === "90d"
  );
}

function formatCurrency(value: unknown): string {
  const n = Number(value ?? 0);
  if (!Number.isFinite(n)) return "—";
  const sign = n < 0 ? "-" : "";
  const abs = Math.abs(n);
  if (abs > 0 && abs < 0.01) return "<$0.01";
  const format = (next: number) => formatNumberRoundedDown(next, 2);
  if (abs >= 1e9) return `${sign}$${format(abs / 1e9)}B`;
  if (abs >= 1e6) return `${sign}$${format(abs / 1e6)}M`;
  if (abs >= 1e3) return `${sign}$${format(abs / 1e3)}K`;
  return `${sign}$${format(abs)}`;
}

function formatTokenPrice(value: unknown): string {
  const n = Number(value ?? 0);
  if (!Number.isFinite(n)) return "—";
  if (n > 0 && n < 0.0001) return "<$0.0001";
  if (n < 1) return `$${n.toFixed(6)}`;
  return `$${n.toFixed(4)}`;
}

function truncateAddress(value: string): string {
  if (value.length <= 14) return value;
  return `${value.slice(0, 6)}...${value.slice(-4)}`;
}

function getGeckoTerminalUrl(dex: DexLeaderboardRow): string | null {
  if (!dex.tokenAddress || !dex.tokenChain) return null;

  const chainMapping: Record<string, string> = {
    ethereum: "eth",
    polygon: "polygon_pos",
    arbitrum: "arbitrum",
    base: "base",
    bsc: "bsc",
    near: "near",
    solana: "solana",
    avalanche: "avax",
  };

  const geckoChain =
    chainMapping[dex.tokenChain.toLowerCase()] || dex.tokenChain.toLowerCase();
  return `https://www.geckoterminal.com/${geckoChain}/tokens/${dex.tokenAddress}?embed=1&info=1&swaps=0&grayscale=0&light_chart=0&chart_type=market_cap&resolution=4h`;
}

function getDexName(row: DexLeaderboardRow, fallback = "Unnamed DEX"): string {
  return (
    row.brokerName ||
    row.broker_name ||
    row.name ||
    row.brokerId ||
    row.broker_id ||
    fallback
  );
}

function getLogo(row: DexLeaderboardRow): string | null {
  return row.logo || row.primaryLogo || null;
}

function DexLogo({ dex }: { dex: DexLeaderboardRow }) {
  const name = getDexName(dex);
  const logo = getLogo(dex);
  if (logo)
    return (
      <img
        src={logo}
        alt=""
        className="h-16 w-16 shrink-0 rounded-2xl object-contain"
      />
    );
  return (
    <div className="flex h-16 w-16 shrink-0 items-center justify-center rounded-2xl bg-(--bg-brand) text-lg font-bold text-(--fg-primary)">
      {name.slice(0, 2).toUpperCase()}
    </div>
  );
}

