function TokenInfoCard({
  dex,
  labels,
}: {
  dex: DexLeaderboardRow;
  labels: {
    dexToken: string;
    tokenPrice: string;
    marketCap: string;
    tokenAddress: string;
    copyTokenAddress: string;
  };
}) {
  const [copiedTokenAddress, setCopiedTokenAddress] = useState(false);
  const hasTokenInfo =
    dex.tokenAddress || dex.tokenSymbol || dex.tokenName || dex.tokenImageUrl;
  const geckoTerminalUrl = getGeckoTerminalUrl(dex);
  if (!hasTokenInfo) return null;

  async function copyTokenAddress() {
    if (!dex.tokenAddress) return;
    await navigator.clipboard.writeText(dex.tokenAddress);
    setCopiedTokenAddress(true);
    window.setTimeout(() => setCopiedTokenAddress(false), 2000);
  }

  return (
    <div className="mb-8 rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5">
      <div className="mb-4 flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          {dex.tokenImageUrl ? (
            <img
              src={dex.tokenImageUrl}
              alt=""
              className="h-10 w-10 rounded-full object-cover"
            />
          ) : (
            <div className="flex h-10 w-10 items-center justify-center rounded-full bg-(--bg-brand) text-xs font-bold text-(--fg-primary)">
              {(dex.tokenSymbol || "TK").slice(0, 2).toUpperCase()}
            </div>
          )}
          <div>
            <div className="text-sm font-semibold text-(--fg-primary)">
              {dex.tokenSymbol || labels.dexToken}
            </div>
            <div className="text-xs text-(--fg-secondary)">
              {dex.tokenName || "—"}
            </div>
          </div>
        </div>
        {geckoTerminalUrl && (
          <a
            href={geckoTerminalUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex shrink-0 items-center gap-1.5 rounded-full border border-(--line-subtle) px-3 py-1.5 text-xs font-medium text-(--fg-primary) hover:bg-(--bg-hover)"
          >
            GeckoTerminal <ExternalLink className="h-3.5 w-3.5" />
          </a>
        )}
      </div>
      <div className="grid gap-4 md:grid-cols-3">
        <div>
          <div className="text-[10px] uppercase tracking-[1.5px] text-(--fg-secondary)">
            {labels.tokenPrice}
          </div>
          <div className="mt-1 text-lg font-semibold text-(--fg-primary)">
            {formatTokenPrice(dex.tokenPrice)}
          </div>
        </div>
        <div>
          <div className="text-[10px] uppercase tracking-[1.5px] text-(--fg-secondary)">
            {labels.marketCap}
          </div>
          <div className="mt-1 text-lg font-semibold text-(--fg-primary)">
            {formatCurrency(dex.tokenMarketCap)}
          </div>
        </div>
        <div>
          <div className="text-[10px] uppercase tracking-[1.5px] text-(--fg-secondary)">
            {labels.tokenAddress}
          </div>
          <div className="mt-1 flex items-center gap-2 font-mono text-lg font-semibold text-(--fg-primary)">
            <span>
              {dex.tokenAddress ? truncateAddress(dex.tokenAddress) : "—"}
            </span>
            {dex.tokenAddress && (
              <button
                type="button"
                onClick={copyTokenAddress}
                aria-label={labels.copyTokenAddress}
                className="inline-flex h-7 w-7 items-center justify-center rounded-full text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary)"
              >
                {copiedTokenAddress ? (
                  <Check className="h-3.5 w-3.5 text-(--line-positive)" />
                ) : (
                  <Copy className="h-3.5 w-3.5" />
                )}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function XLogo({ className = "h-4 w-4" }: { className?: string }) {
  return (
    <svg
      viewBox="0 0 24 24"
      aria-hidden="true"
      className={className}
      fill="currentColor"
    >
      <path d="M18.9 2h3.3l-7.2 8.2L23.5 22h-6.7l-5.2-6.8L5.6 22H2.3l7.7-8.8L1.8 2h6.8l4.7 6.2L18.9 2Zm-1.2 17.9h1.8L7.6 4H5.7l12 15.9Z" />
    </svg>
  );
}

function getXHandle(href?: string | null): string {
  if (!href) return "X";
  const rawValue = href.trim();
  if (rawValue.startsWith("@")) return rawValue;

  try {
    const url = new URL(
      rawValue.startsWith("http") ? rawValue : `https://${rawValue}`
    );
    const handle = url.pathname.split("/").filter(Boolean)[0];
    return handle ? `@${handle.replace(/^@/, "")}` : "X";
  } catch {
    const handle = rawValue
      .replace(/^https?:\/\/(www\.)?(twitter\.com|x\.com)\//, "")
      .split(/[/?#]/)[0];
    return handle ? `@${handle.replace(/^@/, "")}` : "X";
  }
}

function DexLinks({
  dex,
  labels,
}: {
  dex: DexLeaderboardRow;
  labels: {
    website: string;
    telegram: string;
    discord: string;
  };
}) {
  const links: Array<{
    label: string;
    href?: string | null;
    icon: LucideIcon | typeof XLogo;
    showLabel?: boolean;
  }> = [
    { label: labels.website, href: dex.websiteUrl, icon: Globe },
    { label: labels.telegram, href: dex.telegramLink, icon: Send },
    { label: labels.discord, href: dex.discordLink, icon: MessageCircle },
    {
      label: getXHandle(dex.xLink),
      href: dex.xLink,
      icon: XLogo,
      showLabel: true,
    },
  ];
  const activeLinks = links.filter(link => Boolean(link.href)) as Array<{
    label: string;
    href: string;
    icon: LucideIcon | typeof XLogo;
    showLabel?: boolean;
  }>;

  if (activeLinks.length === 0) return null;

  return (
    <div className="flex flex-wrap justify-start gap-1.5">
      {activeLinks.map(({ label, href, icon: Icon, showLabel }) => (
        <a
          key={label}
          href={href}
          target="_blank"
          rel="noopener noreferrer"
          title={label}
          aria-label={label}
          className={`inline-flex items-center gap-1.5 rounded-full border border-(--line-subtle) bg-(--bg-tabs) ${showLabel ? "px-2.5" : "px-2"} py-1.5 text-xs font-medium text-(--fg-primary) hover:bg-(--bg-hover)`}
        >
          <Icon className="h-3.5 w-3.5" />
          {showLabel ? label : null}
        </a>
      ))}
    </div>
  );
}

export default function LeaderboardDetailPage() {
  const { t } = useTranslation();
  const location = useLocation();
  const { brokerId } = useParams<{ brokerId: string }>();
  const [searchParams, setSearchParams] = useSearchParams();
  const periodParam = searchParams.get("period");
  const sortParam = searchParams.get("sort") === "fee" ? "fee" : "volume";
  const initialPeriod: DexPeriod = isDexPeriod(periodParam)
    ? periodParam
    : "30d";
  const [period, setPeriod] = useState<DexPeriod>(initialPeriod);
  const [detail, setDetail] = useState<DexBrokerDetail | null>(null);
  const [leaderboardDex, setLeaderboardDex] =
    useState<DexLeaderboardRow | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    window.scrollTo(0, 0);
    document.documentElement.scrollTop = 0;
    document.body.scrollTop = 0;
  }, [location.key, brokerId]);

  useEffect(() => {
    if (!brokerId) return;
    let cancelled = false;
    const initial = detail === null;
    setLoading(initial);
    setRefreshing(!initial);
    setError(null);
    Promise.all([
      fetchDexBrokerDetail(brokerId, period),
      fetchDexLeaderboard({
        sort: sortParam,
        period,
        limit: 20,
        offset: 0,
      }).catch(
        () =>
          ({
            rows: [],
            meta: { total: 0, limit: 0, offset: 0 },
          }) as unknown as {
            rows: DexLeaderboardRow[];
            meta: { total: number; limit: number; offset: number };
          }
      ),
    ])
      .then(([detailData, leaderboardResult]) => {
        if (cancelled) return;
        setDetail(detailData);
        setLeaderboardDex(
          leaderboardResult.rows.find(
            row => row.brokerId === brokerId || row.broker_id === brokerId
          ) || null
        );
      })
      .catch(err => {
        if (!cancelled)
          setError(
            err instanceof Error
              ? err.message
              : t("board.dexDetailErrorLoadFailed")
          );
      })
      .finally(() => {
        if (!cancelled) {
          setLoading(false);
          setRefreshing(false);
        }
      });
    return () => {
      cancelled = true;
    };
  }, [brokerId, period, sortParam]);

  function changePeriod(nextPeriod: DexPeriod) {
    setPeriod(nextPeriod);
    setSearchParams({ period: nextPeriod, sort: sortParam });
  }

  const periodLabel = getPeriodLabel(period, t);
  const periodItems = DEX_PERIODS.map(item => ({
    label: getPeriodLabel(item, t),
    value: item,
  }));
  const dex =
    detail?.dex && leaderboardDex
      ? { ...detail.dex, ...leaderboardDex }
      : detail?.dex;
  const dexName = dex ? getDexName(dex, t("board.unnamedDex")) : "DEX";
  const linkLabels = {
    website: t("board.website"),
    telegram: "Telegram",
    discord: "Discord",
  };
  const tokenInfoLabels = {
    dexToken: t("board.dexToken"),
    tokenPrice: t("board.tokenPrice"),
    marketCap: t("board.marketCapLabel"),
    tokenAddress: t("board.tokenAddress"),
    copyTokenAddress: t("board.copyTokenAddress"),
  };

  return (
    <div className="min-h-screen bg-(--bg-base)">
      <section className="relative overflow-hidden px-6 py-12">
        <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_at_top,var(--bg-brand-subtle),transparent_58%)]" />
        <div className="relative mx-auto max-w-[1100px]">
          <LocalizedLink
            to="/board"
            className="mb-6 inline-flex items-center gap-2 text-sm font-medium text-(--fg-secondary) hover:text-(--fg-primary)"
          >
            <ArrowLeft className="h-4 w-4" /> {t("board.backToLeaderboard")}
          </LocalizedLink>

          {loading ? (
            <DetailSkeleton />
          ) : error && !detail ? (
            <OdsAlert type="negative" className="p-4">
              {error}
            </OdsAlert>
          ) : detail && dex ? (
            <div
              className={`transition-opacity duration-200 ${refreshing ? "opacity-70" : "opacity-100"}`}
            >
              <div className="mb-8 overflow-hidden rounded-3xl border border-(--line-subtle) bg-(--bg-surface-primary)">
                <div className="relative overflow-hidden p-6 sm:p-8">
                  {dex.banner && (
                    <img
                      src={dex.banner}
                      alt=""
                      className="absolute inset-0 h-full w-full object-cover opacity-10"
                    />
                  )}
                  <div className="relative flex flex-col gap-6 lg:flex-row lg:items-start lg:justify-between">
                    <div className="flex gap-4">
                      <DexLogo dex={dex} />
                      <div>
                        <h1 className="text-3xl font-semibold text-(--fg-primary) sm:text-4xl">
                          {dexName}
                        </h1>
                        <p className="mt-4 max-w-[680px] text-sm leading-6 text-(--fg-secondary)">
                          {dex.description || t("board.noDescription")}
                        </p>
                        <div className="mt-4">
                          <DexLinks dex={dex} labels={linkLabels} />
                        </div>
                      </div>
                    </div>
                    <div className="flex flex-col gap-3 lg:items-end">
                      {dex.dexUrl && (
                        <OdsButton
                          asChild
                          className="max-w-full"
                          size="medium"
                          variant="highlight"
                        >
                          <a
                            href={dex.dexUrl}
                            target="_blank"
                            rel="noopener noreferrer"
                          >
                            <span className="truncate">
                              {t("board.tradeOnDex", { name: dexName })}
                            </span>
                          </a>
                        </OdsButton>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              <TokenInfoCard dex={dex} labels={tokenInfoLabels} />

              <div className="mb-6 flex flex-wrap items-center gap-2">
                <OdsSegmentedControl
                  ariaLabel={t("board.selectLeaderboardPeriod")}
                  items={periodItems}
                  onValueChange={changePeriod}
                  value={period}
                />
                {refreshing && (
                  <div className="text-xs text-(--fg-secondary)">
                    {t("common.updating")}
                  </div>
                )}
              </div>

              {error && (
                <OdsAlert type="negative" className="mb-4">
                  {error}
                </OdsAlert>
              )}

              <div className="mb-8 grid gap-4 md:grid-cols-3">
                <OdsMetricCard
                  label={t("board.volumeForPeriod", { period: periodLabel })}
                  value={formatCurrency(detail.aggregated.totalVolume)}
                />
                <OdsMetricCard
                  label={t("board.builderRevenue")}
                  value={
                    <span className="text-gradient-positive">
                      {formatCurrency(detail.aggregated.totalBrokerFee)}
                    </span>
                  }
                />
                <OdsMetricCard
                  label={t("board.totalFee")}
                  value={formatCurrency(detail.aggregated.totalFee)}
                />
              </div>

              <div className="overflow-hidden rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary)">
                <div className="border-b border-(--line-subtle) px-5 py-4">
                  <h2 className="text-base font-semibold text-(--fg-primary)">
                    {t("board.dailyBreakdown")}
                  </h2>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full min-w-[760px]">
                    <thead>
                      <tr className="border-b border-(--line-subtle)">
                        <th className="px-4 py-3 text-left text-xs font-medium text-(--fg-secondary)">
                          {t("board.date")}
                        </th>
                        <th className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)">
                          {t("board.volume")}
                        </th>
                        <th className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)">
                          {t("board.takerVolume")}
                        </th>
                        <th className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)">
                          {t("board.makerVolume")}
                        </th>
                        <th className="px-4 py-3 text-right text-xs font-medium text-(--fg-secondary)">
                          {t("board.builderRevenue")}
                        </th>
                      </tr>
                    </thead>
                    <tbody>
                      {detail.daily.map(row => (
                        <tr
                          key={row.date}
                          className="border-b border-(--line-subtle) last:border-b-0"
                        >
                          <td className="px-4 py-3 text-sm text-(--fg-primary)">
                            {row.date}
                          </td>
                          <td className="px-4 py-3 text-right text-sm text-(--fg-primary)">
                            {formatCurrency(row.perp_volume)}
                          </td>
                          <td className="px-4 py-3 text-right text-sm text-(--fg-secondary)">
                            {formatCurrency(row.perp_taker_volume)}
                          </td>
                          <td className="px-4 py-3 text-right text-sm text-(--fg-secondary)">
                            {formatCurrency(row.perp_maker_volume)}
                          </td>
                          <td className="px-4 py-3 text-right text-sm font-semibold text-gradient-positive">
                            {formatCurrency(row.broker_fee)}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          ) : null}
        </div>
      </section>
    </div>
  );
}
